rss.channel:
{% set channel_title = config.title %}
{% set channel_description = config.description %}
{% set channel_link = config.base_url %}

{% if title %}
  {% set channel_title = title %}
{% endif %}
{% if description %}
  {% set channel_description = description %}
{% endif %}

{% if feed_url and feed_url is containing("/tags/") %}
  {% set tag_name = feed_url | replace(from=config.base_url ~ "/tags/", to="") | replace(from="/rss.xml", to="") %}
  {% if tag_name and tag_name is not containing("http") %}
    {% set channel_title = "Tag: " ~ tag_name ~ " | " ~ config.title %}
    {% set channel_description = "Posts tagged with " ~ tag_name ~ "." %}
  {% endif %}
{% endif %}

{% if feed_url and feed_url is containing("/categories/") %}
  {% set category_name = feed_url | replace(from=config.base_url ~ "/categories/", to="") | replace(from="/rss.xml", to="") %}
  {% if category_name and category_name is not containing("http") %}
    {% set channel_title = "Category: " ~ category_name ~ " | " ~ config.title %}
    {% set channel_description = "Posts in " ~ category_name ~ "." %}
  {% endif %}
{% endif %}

{% if current_url %}
  {% set channel_link = current_url %}
{% elif feed_url %}
  {% set channel_link = feed_url | replace(from="rss.xml", to="") %}
{% endif %}

{{ channel_title }}
{{ channel_link }}
{{ channel_description }}
Zola
{{ config.default_language }}

{% set_global feed_last_build = "" %}
{% for page in pages %}
  {% if feed_last_build == "" and page.date %}
    {% set_global feed_last_build = page.date %}
  {% endif %}
{% endfor %}
{% if feed_last_build != "" %}
{{ feed_last_build | date(format="%a, %d %b %Y %H:%M:%S %z") }}
{% else %}
{{ now() | date(format="%a, %d %b %Y %H:%M:%S %z") }}
{% endif %}

{% for page in pages %}


      {{ page.title }}
    {% if page.date %}
    {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {% elif page.updated %}
    {{ page.updated | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {% endif %}
      {{ config.author }}
      {{ page.permalink | safe }}
      {{ page.permalink | safe }}

      {% if page.summary %}{{ page.summary | striptags | safe }}{% elif page.description %}{{ page.description | striptags | safe }}{% else %}{{ page.content | striptags | truncate(length=200) | safe }}{% endif %}

      {{ page.content | safe }}

{% endfor %}
